UPDATE mhdb.TB_SCHEDULE_JOB
   SET JOB_NM = #{job_nm}
	 , JOB_CD = #{job_cd}
	 , JOB_SCHEDULE = #{job_schedule}
	 , JOB_METHOD_CD = #{job_method_cd}
	 , JOB_CLASS = #{job_class}
	 , JOB_TYPE_CD = #{job_type_cd}
	 , JOB_PATH = #{job_path}
	 , JOB_ORDER = #{job_order}
	 , JOB_STATUS_CD = #{job_status_cd}
	 , JOB_USER_ID = #{job_user_id}
	 , JOB_TM = #{job_tm}
	 , JOB_WORKER = #{job_worker}
	 , DESCRIPTION = #{description}
	 , SRC_IP = #{src_ip}
	 , SRC_PORT = #{src_port}
	 , SRC_DBMS_CD = #{src_dbms_cd}
	 , SRC_DB = #{src_db}
	 , SRC_USER = #{src_user}
	 , SRC_PASSWD = #{src_passwd}
	 , SRC_TYPE_CD = #{src_type_cd}
	 , SRC_SQL = #{src_sql}
	 , USE_YN = #{use_yn}
 WHERE JOB_ID = #{job_id}

