SELECT J.SERVER_ID , J.JOB_ID , J.JOB_NM , J.TABLE_ID , J.SOURCE_PATH , J.SOURCE_FILE , J.INFO_PATH , J.INFO_FILE , J.JOB_TM , J.SCHEDULE_YN , J.SCHEDULE_VALUE , J.ERROR_PATH , J.SOURCE_DEL_YN , J.LAST_COL_YN , J.JOB_CD , J.USE_YN , S.SERVER_NM , T.TABLE_CD , T.TABLE_NM FROM mhdb.TB_LOAD_JOB_MST J LEFT OUTER JOIN mhdb.TB_TABLE_INFO T ON J.TABLE_ID = T.TABLE_ID LEFT OUTER JOIN mhdb.TB_SERVER S ON J.SERVER_ID = S.SERVER_ID WHERE 1 = 1
AND J.USE_YN = #{useYn}
AND CAST(J.SERVER_ID AS VARCHAR) = #{serverId}
AND CAST(J.JOB_NM AS VARCHAR) ILIKE '%' || #{jobNm} || '%'
ORDER BY J.JOB_ID

