UPDATE mhdb.TB_BATCH_LIST
   SET JOB_NM = #{job_nm}
	 , JOB_TYPE_CD = #{job_type_cd}
	 , JOB_PATH = #{job_path}
	 , JOB_ORDER = #{job_order}
	 , JOB_STATUS_CD = #{job_status_cd}
	 , JOB_USER_ID = #{job_user_id}
	 , JOB_TM = #{job_tm}
	 , JOB_WORKER = #{job_worker}
	 , DESCRIPTION = #{description}
	 , SRC_SQL = #{src_sql}
	 , USE_YN = #{use_yn}
 WHERE JOB_ID = #{job_id}

UPDATE mhdb.TB_BATCH_LIST
   SET JOB_STATUS_CD = #{jobStatusCd}
	 , REPORT_SQL = #{srcSql}
 WHERE JOB_ID = #{jobId}
